mapper.select:
SELECT COUNT(*)
FROM declare_hospital
WHERE province_code = #{provinceCode}

SELECT
    project_type AS typeValue,
    COUNT(*) AS projectCount,
    ROUND(
        COUNT(*) * 100.0 / NULLIF((
            SELECT COUNT(*) FROM declare_hospital
            WHERE project_type BETWEEN 1 AND 6 AND province_code = #{provinceCode}
        ), 0), 1
    ) AS percentage
FROM declare_hospital
WHERE project_type BETWEEN 1 AND 6 AND province_code = #{provinceCode}
GROUP BY project_type
ORDER BY project_type
